export function centerExtent(start, end){
	let q = Math.pow( 2, Math.ceil( Math.log2( end - start ) ) ),
			s = Math.floor( (end + start - q) / 2 ),
			e = s + q;

	return [ s, e ];
}
export function leftExtent(start, end){
	let q = Math.pow( 2, Math.ceil( Math.log2( end - start ) ) ),
			s = Math.floor( start ),
			e = s + q;

	return [ s, e ];
}
export function rightExtent(start, end){
	let q = Math.pow( 2, Math.ceil( Math.log2( end - start ) ) ),
			e = Math.ceil( end ),
			s = e - q;

	return [ s, e ];
}

export function isOver(start, end, num){
	if( start > num ){
		return [ num, end ];
	}else if( end < num ){
		return [ start, num ];
	}else{
		return false;
	}
}

export function extentX(x0, x1){
	if( x0 > this.x0 ){
		x0 = this.x0;
	}
	if( x1 < this.x1 ){
		x1 = this.x1;
	}
	[this.x0, this.x1] = leftExtent(x0, x1);
	return this;
}

export function extentY(y0, y1){
	if( y0 > this.y0 ){
		y0 = this.y0;
	}
	if( y1 < this.y1 ){
		y1 = this.y1;
	}
	[this.y0, this.y1] = leftExtent(y0, y1);
	return this;
}

export default function extent(x0, y0, x1, y1){
	this.extentX(x0, x1);
	this.extentY(y0, y1);
	return this;
}




