<template>
	<div
		class="container"
		ref="container"></div>
</template>

<script>
	import * as d3 from 'd3'
	import getQuadtree from './d3-quadtree/quadtree.js'

	export default {
		data(){
			return {
				quadtree: null,
				width: 512,
				height: 512,
				svg: null
			}
		},
		mounted(){
			let container = this.$refs.container,
					width = 512,
					height = 512,
					quadtree = this.quadtree = getQuadtree({
						getX(data){
							return data.x;
						},
						getY(data){
							return data.y;
						}
					}).extent(0,0,512,512),
					svg = this.svg = d3.select(container)
						.append('svg')
						.attr( 'width', this.width )
						.attr( 'height', this.height )
						.style("font", "12px sans-serif");

			window.add = this.add.bind(this);
			window.remove = this.remove.bind(this);
		},
		methods: {
			add(){//svg添加的方式需要优化
				let svg = this.svg;
				this.quadtree.add({
					x: Math.floor(Math.random() * this.width),
					y: Math.floor(Math.random() * this.height)
				}).initRange();

				svg.selectAll(".node").remove();
				svg.selectAll(".point").remove();

				svg.selectAll(".node")
					.data(this.quadtree.toArray())
					.enter().append("rect")
					.attr("class", "node")
					.attr("x", function(d) { return d.x0; })
					.attr("y", function(d) { return d.y0; })
					.attr("width", function(d) { return d.y1 - d.y0; })
					.attr("height", function(d) { return d.x1 - d.x0; });

				svg.selectAll(".point")
					.data(this.quadtree.toArray(true))
						.attr("class", "point")
						.attr("cx", function(d) { return d.data.x; })
						.attr("cy", function(d) { return d.data.y; })
						.attr("r", 1);

				svg.selectAll(".point")
					.data(this.quadtree.toArray(true))
					.enter().append("circle")
						.attr("class", "point")
						.attr("cx", function(d) { return d.data.x; })
						.attr("cy", function(d) { return d.data.y; })
						.attr("r", 1);
			},
			remove(i){//有问题，需完善
				let node = this.quadtree.toArray(true)[i].data;
				this.quadtree.remove(node);
				console.log('this.quadtree:',this.quadtree);

				let svg = this.svg;

				svg.selectAll(".node").remove();
				svg.selectAll(".point").remove();

				svg.selectAll(".node")
					.data(this.quadtree.toArray())
					.enter().append("rect")
					.attr("class", "node")
					.attr("x", function(d) { return d.x0; })
					.attr("y", function(d) { return d.y0; })
					.attr("width", function(d) { return d.y1 - d.y0; })
					.attr("height", function(d) { return d.x1 - d.x0; });

				svg.selectAll(".point")
					.data(this.quadtree.toArray(true))
						.attr("class", "point")
						.attr("cx", function(d) { return d.data.x; })
						.attr("cy", function(d) { return d.data.y; })
						.attr("r", 1);

				svg.selectAll(".point")
					.data(this.quadtree.toArray(true))
					.enter().append("circle")
						.attr("class", "point")
						.attr("cx", function(d) { return d.data.x; })
						.attr("cy", function(d) { return d.data.y; })
						.attr("r", 1);

			}
		}
	}
</script>

<style lang="less">
	.point {
		fill: #000;
		fill-opacity: 0.4;
	}
	.point--scanned {
		fill: orange;
		fill-opacity: 1;
		stroke: orange;
		stroke-width: 3px;
	}

	.point--selected {
		fill: red;
		fill-opacity: 1;
		stroke: red;
		stroke-width: 5px;
	}
	.node {
		fill: none;
		stroke: #ccc;
		shape-rendering: crispEdges;
	}
</style>